	let i = i32(floor(x + s));
	let j = i32(floor(y + s));
	let k = i32(floor(z + s));
	let t = f32(i + j + k) * SIMPLEX_G3;
	let x0 = x - (f32(i) - t);
	let y0 = y - (f32(j) - t);
	let z0 = z - (f32(k) - t);

	var i1 = 0;
	var j1 = 0;
	var k1 = 0;
	var i2 = 0;
	var j2 = 0;
	var k2 = 0;

	if (x0 >= y0) {
		if (y0 >= z0) {
			i1 = 1; j1 = 0; k1 = 0;
			i2 = 1; j2 = 1; k2 = 0;
		} else if (x0 >= z0) {
			i1 = 1; j1 = 0; k1 = 0;
			i2 = 1; j2 = 0; k2 = 1;
		} else {
			i1 = 0; j1 = 0; k1 = 1;
			i2 = 1; j2 = 0; k2 = 1;
		}
	} else if (y0 < z0) {
		i1 = 0; j1 = 0; k1 = 1;
		i2 = 0; j2 = 1; k2 = 1;
	} else if (x0 < z0) {
		i1 = 0; j1 = 1; k1 = 0;
		i2 = 0; j2 = 1; k2 = 1;
	} else {
		i1 = 0; j1 = 1; k1 = 0;
		i2 = 1; j2 = 1; k2 = 0;
	}

